1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Array<[number, number]> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0],           [1, 0],
6	  [-1, 1],  [0, 1],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export function nextGeneration(liveCells: Array<Cell>): Array<Cell> {
12	  const liveSet = new Set<string>(liveCells.map(([x, y]) => cellKey(x, y)));
13	  const neighborTallies = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const k = cellKey(nx, ny);
20	      const existing = neighborTallies.get(k);
21	      if (existing) existing.count++;
22	      else neighborTallies.set(k, { cell: [nx, ny], count: 1 });
23	    }
24	  }
25	
26	  const result: Array<Cell> = [];
27	  for (const [k, { cell, count }] of neighborTallies) {
28	    if (count === 3 || (count === 2 && liveSet.has(k))) result.push(cell);
29	  }
30	  return result;
31	}
